idiomaticSolution:
fn parse_config(input: &str) -> Result<(String, u32), Box<dyn std::error::Error>> {
    let (name, port_str) = input.split_once(':').ok_or("missing delimiter")?;
    let port = port_str.parse::<u32>()?;
    Ok((name.to_string(), port))
}
